import java.util.TreeMap;

class CountIntervals {

    private TreeMap<Integer, Integer> map;
    private int count;

    public CountIntervals() {
        map = new TreeMap<>();
        count = 0;
    }

    public void add(int left, int right) {
        if (left > right) return;
        Map.Entry<Integer, Integer> entry = map.ceilingEntry(left);
        int start = left;
        while (entry != null && entry.getKey() <= right) {
            if (entry.getValue() >= right) return;
            if (entry.getValue() >= start) {
                start = entry.getValue() + 1;
            }
            map.remove(entry.getKey());
            entry = map.ceilingEntry(start);
        }
        map.put(start, right);
        count += right - start + 1;
    }

    public int count() {
        return count;
    }
}
```
